mapper.select:
SELECT t.id, t.registration_id, t.patient_id, p.patient_name,
       t.treatment_name, t.treatment_desc, t.fee, t.status, t.treatment_time
FROM treatment t
LEFT JOIN patient p ON t.patient_id = p.id

    AND t.registration_id = #{registrationId}
    AND t.patient_id = #{patientId}
    AND t.registration_id IN (SELECT r.id FROM registration r WHERE r.doctor_id = #{doctorId})
    AND t.status = #{status}

ORDER BY t.treatment_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM treatment t

    AND t.registration_id = #{registrationId}
    AND t.patient_id = #{patientId}
    AND t.registration_id IN (SELECT r.id FROM registration r WHERE r.doctor_id = #{doctorId})
    AND t.status = #{status}
